{
  "summary": "This paper introduces AmbiBench, a novel benchmark designed to study task ambiguity in language models and humans through six ambiguously-specified binary classification tasks. The study empirically demonstrates that large-scale RLHF-trained models outperform others and humans in disambiguating tasks from instructions and examples, and proposes finetuning on ambiguous examples as a promising strategy to improve model robustness.",
  "strengths": [
    {
      "point": "Novel benchmark addressing task ambiguity",
      "evidence": "AmbiBench consists of six ambiguously-specified binary classification tasks with paired linguistic features, enabling systematic evaluation of task ambiguity distinct from input ambiguity."
    },
    {
      "point": "Comprehensive empirical evaluation",
      "evidence": "The paper evaluates a variety of models including RLHF-trained and instruction-tuned models, as well as human participants, across different instruction informativeness levels and numbers of labeled examples."
    },
    {
      "point": "Insightful finetuning experiments",
      "evidence": "Finetuning on ambiguous in-context examples significantly improves standard language models’ ability to resolve ambiguity, closing the gap with RLHF models and suggesting a mechanism behind RLHF success."
    },
    {
      "point": "Clear problem motivation and distinction",
      "evidence": "The paper clearly distinguishes task ambiguity from input ambiguity and motivates the importance of studying task ambiguity for real-world applications."
    }
  ],
  "weaknesses": [
    {
      "point": "Limited comparison to prior ambiguity-related benchmarks",
      "evidence": "The paper lacks thorough literature review and empirical comparison to existing ambiguity or instruction tuning datasets such as SuperGLUE."
    },
    {
      "point": "Insufficient justification for selected paired feature categories",
      "evidence": "No explanation is provided for why specific linguistic feature pairs were chosen or whether other ambiguity types were considered."
    },
    {
      "point": "Lack of analysis on template complexity and naturalness",
      "evidence": "No ablation or discussion on how template design affects model or human performance, limiting understanding of real-world applicability."
    },
    {
      "point": "Evaluation limited to a narrow set of models",
      "evidence": "Popular instruction-tuned or RLHF models like GPT-4, PaLM, or open-source models such as LLaMA and Falcon are not evaluated."
    },
    {
      "point": "Confounding of RLHF effects with model size",
      "evidence": "RLHF models tested are also the largest, making it difficult to isolate the effect of RLHF from scale without controlled experiments."
    },
    {
      "point": "Evaluation metrics limited to accuracy",
      "evidence": "No additional metrics such as confidence calibration, error analysis, or response consistency are reported to deepen understanding of ambiguity resolution."
    },
    {
      "point": "Prompt format sensitivity not systematically explored",
      "evidence": "Although T0++ shows prompt format sensitivity, no comprehensive analysis across models is conducted."
    },
    {
      "point": "Reproducibility hindered by missing details",
      "evidence": "Template generation details, code, and finetuning hyperparameters are not sufficiently described."
    },
    {
      "point": "Ambiguity definition lacks precision",
      "evidence": "No formal or operational definition or taxonomy of task ambiguity is provided."
    },
    {
      "point": "Speculative claims about RLHF’s role",
      "evidence": "The suggestion that RLHF models’ superior performance stems from ambiguous-example training is not empirically validated."
    },
    {
      "point": "Limited task scope and human evaluation details",
      "evidence": "Only binary classification tasks are included, and human evaluation participant details and protocols are sparse."
    },
    {
      "point": "Generalisability to naturalistic, multilingual, or complex tasks unclear",
      "evidence": "Use of templated sentences and English-only experiments limit understanding of applicability to real-world or multilingual settings."
    }
  ],
  "questions": [
    {
      "question": "How does AmbiBench compare empirically to existing ambiguity or instruction tuning benchmarks?",
      "motivation": "To better position the novelty and utility of AmbiBench relative to prior work."
    },
    {
      "question": "Can the effects of RLHF be disentangled from model size through controlled experiments?",
      "motivation": "To clarify whether RLHF or scale drives improved ambiguity resolution."
    },
    {
      "question": "How would models perform on more naturalistic, less templated ambiguous tasks or in multilingual settings?",
      "motivation": "To assess the generalisability and real-world relevance of the findings."
    },
    {
      "question": "What is the impact of prompt design on ambiguity resolution across different models?",
      "motivation": "Prompt engineering may significantly affect model robustness and should be systematically studied."
    },
    {
      "question": "Could additional metrics beyond accuracy provide deeper insights into model behavior on ambiguous tasks?",
      "motivation": "Understanding confidence, error types, and consistency could inform model improvements."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
